workspace_files.test_retry.py:
from retry import retry
calls={'n':0}
@retry(3)
def flaky():
    calls['n']+=1
    if calls['n']<3: raise ValueError('boom')
    return 'done'
assert flaky()=='done'
assert calls['n']==3
print('ok')

